CHAPTERS = [
 {"slug":"ch01-mudanca-de-poder","sub":"CAPÍTULO 1: A Mudança de Poder",
  "intro":"O microfone trocou de dono. O poder que era das marcas passou para o cliente conectado, e a relação que descia de cima para baixo virou conversa de igual para igual. Hoje o cliente confia mais na rede do que na propaganda — e a rede só dá ouvidos a quem merece.",
  "cards":[
      {"ic":"link","t":"O Poder Mudou de Mãos","emph":"Mudou de Mãos","b":"Três viragens redesenharam o jogo: do <strong>exclusivo para o inclusivo</strong>, do vertical para o horizontal, do individual para o social. A marca perdeu o microfone — não dita mais a conversa, entra nela como mais uma voz, e disputa atenção como qualquer outra. Quem manda agora é a rede do cliente, e ela só ouve quem merece ser ouvido.","tip":"<strong>Modelo mental:</strong> na era conectada a marca não vence falando mais alto. Vence merecendo ser repetida quando ela não está na sala."},
      {"ic":"constellation","t":"A Nova Autoridade é Horizontal","emph":"Horizontal","b":"O cliente confia no <strong>fator-F — Friends, Families, Fans e Followers</strong> — acima das marcas e até dos especialistas. A nota de um desconhecido na internet pode pesar mais que o parecer do perito de jaleco. A confiança desceu do pedestal vertical e se espalhou na horizontal — e a recomendação do par virou a mídia mais barata e mais cara que existe ao mesmo tempo.","tip":"<strong>Como aplicar:</strong> trate cada cliente satisfeito como um canal de mídia. Na rede, ele é exatamente isso — e cobra em confiança, não em verba."},
      {"ic":"scale","t":"A Zona O da Decisão","emph":"Zona O","b":"Toda compra é puxada por três forças: <strong>Externa</strong> (o anúncio da marca), <strong>Outros</strong> (a comunidade, o boca a boca) e <strong>Própria</strong> (a experiência vivida). Quanto mais conectado o cliente, mais o peso desliza para “Outros”. Despejar tudo no anúncio é gritar justamente no canal que menos decide.","tip":"<strong>Regra:</strong> faça crescer “Outros” e “Própria”. A propaganda abre a porta — quem fecha a venda é o que os outros dizem e o que o cliente sente."},
      {"ic":"eye","t":"O Cliente Pergunta Antes","emph":"Pergunta","b":"Antes de decidir, o cliente conectado pesquisa, compara e interroga a rede: a venda se ganha ou se perde nas avaliações e nos grupos, muito antes do balcão. Fingir que esse território não existe não o faz sumir. <strong>Tratar o cliente como receptor passivo de propaganda é remar contra a maré da era digital.</strong>","tip":"<strong>Sinal de alerta:</strong> se você não está onde o cliente pergunta, outra resposta chega primeiro — e o nome dela costuma ser concorrente.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 1",
  "lessons":["O poder é do cliente conectado: a marca conquista, não comanda.","O fator-F é a nova autoridade — a rede pesa mais que o anúncio.","Faça crescer 'Outros' (advocacia) e 'Própria' (experiência), não só o anúncio."]},

 {"slug":"ch02-subculturas-jmn","sub":"CAPÍTULO 2: As Subculturas JMN",
  "intro":"Nem todo cliente vale o mesmo na hora de espalhar uma ideia. Há três grupos que os outros olham e imitam — e quem conquista esses três conquista, por tabela, o mercado inteiro.",
  "cards":[
      {"ic":"constellation","t":"Os Três que Movem o Resto","emph":"Três","b":"Na era digital, três subculturas comandam a decisão coletiva: <strong>Jovens</strong> adotam o novo primeiro e definem o que é tendência; <strong>Mulheres</strong> pesquisam, comparam e decidem a maior parte do consumo da casa; <strong>Netizens</strong> conectam, avaliam e evangelizam nas redes. Conquistar JMN não é falar com todo mundo — é falar com quem todo mundo segue.","tip":"<strong>Como aplicar:</strong> esqueça “o público em geral”, que não existe. Mire os três segmentos que puxam o resto e deixe a influência fazer o transporte.","wide":True},
      {"ic":"bulb","t":"Mente, Mercado e Coração","emph":"Mente, Mercado e Coração","b":"Cada subcultura guarda um cofre diferente da influência: os Jovens detêm o <strong>mind share</strong> (a cabeça, o que vira moda), as Mulheres o <strong>market share</strong> (a mão que abre a carteira) e os Netizens o <strong>heart share</strong> (o coração que contagia). Três cofres, três fechaduras — e nenhuma chave-mestra que abra os três de uma vez.","tip":"<strong>Modelo mental:</strong> a mensagem que seduz a cabeça do jovem não é a que toca o coração do netizen. Adapte o argumento ao cofre que quer abrir."},
      {"ic":"target","t":"Influência Vale Mais que Alcance","emph":"Influência","b":"Falar com milhões que não formam opinião é gastar fôlego à toa. <strong>Audiência grande não é o mesmo que mercado movido</strong> — o que conta é atingir quem os outros copiam. Jovens dão a tendência, mulheres dão a decisão, netizens dão a paixão; juntos cobrem as três rotas por onde a influência viaja.","tip":"<strong>Regra:</strong> conte quem você convence, não quantos você alcança. Um conector que repassa vale mais que mil espectadores mudos."},
    ],
  "lessons_title":"Lições-Chave do Capítulo 2",
  "lessons":["Mire JMN — Jovens, Mulheres e Netizens puxam o resto do mercado.","Mente, mercado e coração são cofres distintos: cada um pede sua chave.","Influência (quem você convence) vale mais que alcance bruto (quantos você atinge)."]},

 {"slug":"ch03-quatro-eras","sub":"CAPÍTULO 3: As Quatro Eras do Marketing",
  "intro":"O 4.0 não joga fora o que veio antes — ele empilha. Cada era do marketing somou um centro de gravidade ao anterior, e o digital é a camada que costura todas. Quem trata o 4.0 como ruptura entende metade da história.",
  "cards":[
      {"ic":"steps","t":"De 1.0 a 4.0","emph":"1.0 a 4.0","b":"Quatro eras, cada uma com seu eixo, nenhuma apagando a anterior: <strong>1.0</strong> centrado no produto (vender o que a fábrica produz), <strong>2.0</strong> no cliente (satisfazer e reter o rei), <strong>3.0</strong> no humano e nos valores (a marca com alma e propósito), <strong>4.0</strong> no digital — que põe os três a operar na economia conectada.","tip":"<strong>Modelo mental:</strong> o 4.0 não substitui o 3.0, o 2.0 e o 1.0 — carrega os três dentro de si. É evolução em camadas, não troca de software.","wide":True},
      {"ic":"link","t":"Online Encontra Offline","emph":"Online","b":"O digital <strong>não substitui o físico — casa com ele</strong>. É estilo (a tecnologia) a serviço da substância (os valores humanos): por trás de cada máquina, a conexão continua sendo de gente para gente. A loja, o app e a conversa de verdade são portas da mesma casa, não mundos rivais.","tip":"<strong>Como aplicar:</strong> use o digital para aproximar pessoas, jamais como desculpa para dispensá-las. A máquina escala o alcance; o humano é que gera o vínculo."},
      {"ic":"mask","t":"A Armadilha do 100% Digital","emph":"100% Digital","b":"Largar o offline e o calor humano para virar tudo digital é ler o mapa de cabeça para baixo: <strong>tecnologia sem humanidade esfria a marca</strong>. E confundir 4.0 com “anúncio na internet” é rebaixá-lo — ele não é uma mídia a mais, é a centralidade humana do 3.0 funcionando sob a conectividade.","tip":"<strong>Sinal de alerta:</strong> automação que apaga o contato em vez de qualificá-lo afasta justamente o cliente que você queria para a vida toda.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 3",
  "lessons":["4.0 = produto + cliente + humano, agora operando no digital conectado.","Online e offline convergem numa só experiência — nenhum vence sozinho.","Tecnologia é estilo a serviço da substância humana, nunca o contrário."]},

 {"slug":"ch04-cinco-as","sub":"CAPÍTULO 4: Os Cinco As — A Jornada do Cliente",
  "intro":"O funil reto morreu. No lugar entrou uma espiral, moldada pela comunidade, em que o cliente vai e volta, pergunta e reconsidera. E a linha de chegada se mudou de lugar: já não basta vender — é preciso transformar o comprador em quem defende a marca.",
  "cards":[
      {"ic":"spiral","t":"A Jornada dos Cinco As","emph":"Cinco As","b":"O caminho do cliente em cinco fases: <strong>Assimilação</strong> (toma conhecimento), <strong>Atração</strong> (algumas marcas “grudam”), <strong>Arguição</strong> (pesquisa e compara), <strong>Ação</strong> (compra e usa) e <strong>Apologia</strong> (recomenda sem que peçam). Cada passagem de uma fase à outra é uma porta — e em toda porta a marca pode ganhar ou perder o cliente.","tip":"<strong>Como aplicar:</strong> posicione seus clientes nas cinco fases e localize a porta por onde eles vazam. É lá, e não no slogan, que mora o problema.","wide":True},
      {"ic":"link","t":"Não É Mais um Funil","emph":"Funil","b":"O funil só sabia estreitar; a jornada de hoje é uma <strong>espiral social, não uma queda solitária</strong>. A Arguição pode reacender a Atração, a comunidade empurra adiante e de volta, e entre gostar e comprar quem decide é a opinião alheia. O caminho dobra, repete e se ramifica — desenhá-lo como tubo é desenhar o cliente errado.","tip":"<strong>Modelo mental:</strong> pare de imaginar o cliente caindo por um funil. Imagine-o girando numa espiral que a rede gira junto com ele."},
      {"ic":"target","t":"A Apologia é o Novo Topo","emph":"Novo Topo","b":"Lealdade já não se mede por recompra, e sim por <strong>disposição de recomendar</strong>. O defensor traz clientes novos sem custo e com a credibilidade que verba alguma compra. Por isso o alvo se deslocou para a Apologia: a venda é apenas a metade do caminho — quem para nela deixa o melhor em cima da mesa.","tip":"<strong>Regra:</strong> submeta cada iniciativa a uma pergunta — “isto faz alguém querer recomendar?”. Se a resposta é não, você gerou transação, não advocacia."},
      {"ic":"pin","t":"Ação Não É Só a Venda","emph":"Só a Venda","b":"A Ação abraça a <strong>experiência inteira de uso e de serviço</strong>, e é ela — não o ato de pagar — que decide se virá a Apologia. Tomar a compra por linha de chegada é abandonar o cliente justo no trecho que fabrica (ou mata) a recomendação. O pós-venda não é detalhe: é o berço da lealdade.","tip":"<strong>Sinal de alerta:</strong> sumir depois do pagamento não devolve o cliente ao zero — devolve abaixo dele, como um detrator silencioso.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 4",
  "lessons":["Mapeie o cliente nos cinco As e ache a porta por onde ele vaza.","Projete para a Apologia, não só para a Ação — a venda é meio caminho.","A experiência pós-compra faz parte da Ação, e é ela que decide a recomendação."]},

 {"slug":"ch05-par-bar","sub":"CAPÍTULO 5: PAR e BAR — A Produtividade do Marketing",
  "intro":"Mapeada a jornada, falta medi-la. Duas razões — só duas — dizem onde o marketing rende e onde escoa pelo ralo. Quem não as calcula gere o que não enxerga.",
  "cards":[
      {"ic":"target","t":"PAR e BAR","emph":"PAR e BAR","b":"Duas frações sintetizam toda a jornada. <strong>PAR</strong> (Taxa de Ação de Compra): dos que conhecem a marca, quantos chegam à Ação — quanto da consciência vira compra. <strong>BAR</strong> (Taxa de Defesa da Marca): dos que conhecem, quantos chegam à Apologia. Na era conectada o BAR é o número que manda, porque defensor é crescimento que não aparece na fatura de mídia.","tip":"<strong>Como aplicar:</strong> projete cada campanha para subir o BAR, não para inchar impressões. Impressão você paga uma vez; o defensor trabalha de graça para sempre.","wide":True},
      {"ic":"gap","t":"O Gargalo Revela Onde Agir","emph":"Gargalo","b":"A maior queda entre duas fases — muita Atração e pouca Arguição, digamos — aponta com o dedo <strong>onde o marketing está vazando</strong>. Polir o que já vai bem é vaidade cara; o ganho mora em desentupir o ponto que estrangula a passagem. Diagnosticar o gargalo já é metade do conserto.","tip":"<strong>Regra:</strong> antes de gastar, encontre a transição mais fraca. É ali, e não no trecho que já brilha, que cada real rende dobrado."},
      {"ic":"scale","t":"Produtividade, Não Vaidade","emph":"Vaidade","b":"Alcance imenso com BAR rasteiro é <strong>ser visto e esquecido no mesmo segundo</strong> — encher o balde furado enquanto se comemora a torneira aberta. Métricas de vaidade (impressões, alcance bruto) seduzem porque incham fácil; só a conversão entre fases revela se houve resultado ou apenas ruído bem-iluminado.","tip":"<strong>Sinal de alerta:</strong> festejar Assimilação altíssima com PAR e BAR no chão é confundir movimento com progresso — andar muito sem sair do lugar.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 5",
  "lessons":["Meça PAR (consciência→compra) e BAR (consciência→recomendação).","Ataque o gargalo — a transição mais fraca —, não o que já funciona.","BAR é a métrica do crescimento orgânico: projete deliberadamente para ela."]},

 {"slug":"ch06-quatro-cs","sub":"CAPÍTULO 6: Os Quatro Cs — O Novo Mix",
  "intro":"Os 4 Ps nasceram num mundo em que a marca decidia tudo e o cliente só aparecia para pagar. Esse mundo acabou. Na economia conectada cada P se abre num C, e o cliente que era plateia sobe ao palco.",
  "cards":[
      {"ic":"layers","t":"De 4 Ps a 4 Cs","emph":"4 Cs","b":"O mix clássico foi desenhado para o monólogo da marca. A conectividade o reescreve em quatro <strong>Cs que chamam o cliente para dentro</strong>: Produto → Co-criação, Preço → Moeda, Praça → Ativação comunitária, Promoção → Conversa. O cliente deixou de ser destinatário e virou participante.","tip":"<strong>Modelo mental:</strong> de monólogo a diálogo. O cliente já não entra só pelo caixa — entra também na fábrica e na vitrine.","wide":True},
      {"ic":"link","t":"Co-criação e Ativação","emph":"Co-criação","b":"<strong>Co-criar</strong> é fazer do cliente coautor desde a ideação: o produto erra menos e nasce com o aval de quem ajudou a moldá-lo. <strong>Ativação comunitária</strong> é deixar a própria rede distribuir e vender, de par a par — a “praça” deixa de ser o ponto físico e passa a ser a comunidade que recomenda. Quem participa da criação não compra: defende.","tip":"<strong>Como aplicar:</strong> chame a comunidade para antes do lançamento, não para depois do anúncio. O coautor já vem convertido."},
      {"ic":"bubble","t":"Moeda e Conversa","emph":"Conversa","b":"<strong>Moeda</strong> aposenta a tabela fixa em favor do preço dinâmico, por valor e por assinatura, que responde à demanda e ao momento. <strong>Conversa</strong> aposenta o anúncio unilateral: a promoção que rende é a que vira diálogo entre clientes. Falar sem escutar não produz apologia — produz ruído com logotipo.","tip":"<strong>Sinal de alerta:</strong> promoção que só transmite e nunca responde trata o cliente como ouvinte, e ouvinte não recomenda — interlocutor recomenda.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 6",
  "lessons":["Co-crie em vez de só lançar — quem ajuda a criar, defende.","Pense preço como moeda dinâmica, não como tabela fixa.","Troque a promoção unilateral por conversa: monólogo não gera apologia."]},

 {"slug":"ch07-humano-conteudo","sub":"CAPÍTULO 7: Marketing Humano e de Conteúdo",
  "intro":"Para atrair na Atração e responder na Arguição, a marca precisa de duas coisas que o anúncio não dá: parecer gente e ser útil de graça. Em vez de interromper, ela ganha o direito de ser ouvida.",
  "cards":[
      {"ic":"mask","t":"A Marca Precisa Parecer Gente","emph":"Gente","b":"Para atrair, a marca veste <strong>seis atributos humanos: fisicalidade, intelectualidade, sociabilidade, emocionalidade, personalidade e moralidade</strong>. Marca com opiniões, empatia, defeitos charmosos e — acima de tudo — princípios à mostra gera o que polimento nenhum compra: confiança. A perfeita e sem rosto desperta menos afeto que a que tem alma e assume.","tip":"<strong>Modelo mental:</strong> marca com alma vence marca impecável. O cliente não se apaixona pelo que não tem cara.","wide":True},
      {"ic":"book","t":"Conteúdo é a Nova Propaganda","emph":"Nova Propaganda","b":"Em vez de interromper, a marca <strong>oferece conteúdo útil que responde à Arguição do cliente</strong> — educa, ajuda, diverte. Quem já entregou algo valioso sobre o tema chega como aliado, não como vendedor, e por isso é convidado para a conversa em vez de ser bloqueado. A ordem é uma só: útil primeiro, venda depois.","tip":"<strong>Como aplicar:</strong> antes de pedir a compra, entregue algo que o cliente guardaria mesmo se nunca comprasse nada de você."},
      {"ic":"bulb","t":"Alimentar a Influência 'Outros'","emph":"Outros","b":"O conteúdo abastece o fator-F e a comunidade — a influência “Outros”, a que <strong>mais pesa na decisão de hoje</strong>. Mas o cliente conectado tem faro de cão: anúncio fantasiado de conteúdo é farejado e descartado no mesmo gesto. Só o que serve de verdade alimenta a conversa e volta como recomendação.","tip":"<strong>Sinal de alerta:</strong> se o “conteúdo” só funciona quando vende, ele não é conteúdo — é anúncio disfarçado, e queima a confiança que dizia construir.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 7",
  "lessons":["Dê à marca os seis atributos humanos — inclusive, e sobretudo, moralidade.","Faça marketing de conteúdo: seja útil primeiro, venda depois.","Conteúdo abastece a influência 'Outros' — o motor da decisão na era conectada."]},

 {"slug":"ch08-omnichannel-engajamento","sub":"CAPÍTULO 8: Omnichannel e Engajamento",
  "intro":"As duas últimas táticas fecham a espiral. O omnichannel tira o atrito da Ação; o engajamento cultiva a afinidade que matura em Apologia. E há um alvo único que liga as duas: o momento UAU, a surpresa que faz o cliente abrir a boca para falar de você.",
  "cards":[
      {"ic":"link","t":"Omnichannel e O2O","emph":"Omnichannel","b":"Costurar os pontos de contato <strong>online e offline numa experiência sem emenda</strong> — o O2O (online-to-offline). O cliente pesquisa no app, compra na loja e é reconhecido nos dois, sem recomeçar do zero a cada troca de canal. A marca é uma só casa; cada canal é apenas uma porta, e nenhuma porta pode obrigar o cliente a se reapresentar.","tip":"<strong>Como aplicar:</strong> faça a marca reconhecer o mesmo cliente em todo canal. A costura entre eles é como a de uma boa roupa — só funciona quando não aparece.","wide":True},
      {"ic":"spark","t":"O Momento UAU","emph":"UAU","b":"A experiência que surpreende — <strong>prazerosa, envolvente, memorável</strong> — é o gatilho que dispara a Apologia e puxa o BAR para cima. O “UAU” fecha a espiral dos cinco As, convertendo quem comprou em quem recomenda. E essa surpresa não cabe num anúncio: ninguém recomenda uma promessa, recomenda-se o que foi vivido.","tip":"<strong>Regra:</strong> desenhe de propósito um instante de encantamento no uso. É ele, e não o slogan, que arranca a frase “precisa conhecer” da boca do cliente."},
      {"ic":"target","t":"Engajamento com Propósito","emph":"Propósito","b":"Três alavancas cultivam a afinidade: <strong>apps móveis</strong> (utilidade na palma da mão), <strong>CRM social</strong> (ouvir e resolver às claras nas redes) e <strong>gamificação</strong> (níveis, missões, recompensas). Todas a serviço do vínculo, jamais do enfeite. Engajar é aproximar — distrair é o oposto disfarçado.","tip":"<strong>Sinal de alerta:</strong> gamificar por gamificar, sem valor real, é fricção vestida de diversão — o cliente sente o truque e se afasta.","warn":True},
    ],
  "lessons_title":"Lições-Chave do Capítulo 8",
  "lessons":["Integre online + offline numa experiência sem costura (O2O): uma casa, várias portas.","Engaje com apps, CRM social e gamificação — sempre com propósito, nunca de enfeite.","Projete deliberadamente o momento UAU: é ele que dispara a Apologia."]},
]
